UpdateSchema "CIMDATA=<CIMStandardDataConnection xsi:type='typens:CIMStandardDataConnection' xmlns:xsi='http://www.w3.org/2001/XMLSchema-instance' xmlns:xs='http://www.w3.org/2001/XMLSchema' xmlns:typens='http://www.esri.com/schemas/ArcGIS/3.2.0'><WorkspaceConnectionString>ENCRYPTED_PASSWORD_UTF8=00022e68736c49467271537269326f57724d422b78666f4c4c507a4b4266547657467a4350484d745a436730616e733d2a00;ENCRYPTED_PASSWORD=00022e68644164487a526a584372337270524a595951666e3933517433425a664a5048502b4d6374644543545438383d2a00;SERVER=10.0.105.62;INSTANCE=sde:postgresql:10.0.105.62,5444;DBCLIENT=postgresql;DB_CONNECTION_PROPERTIES=10.0.105.62,5444;DATABASE=whgis;USER=sde;VERSION=sde.DEFAULT;AUTHENTICATION_MODE=DBMS</WorkspaceConnectionString><WorkspaceFactory>SDE</WorkspaceFactory><Dataset>whgis.sde.MOSAIC_STICKS_L_F</Dataset><DatasetType>esriDTFeatureClass</DatasetType></CIMStandardDataConnection>" "<operationSequence><workflow><AddAttributeRule><rule_name>Create New Entity</rule_name><rule_type>CALCULATION</rule_type><expression>// This script is designed to run on the 'Add' operation in the OriginTable
// Define the origin feature
var originFeature = $feature


// Check if the feature has been added
if (IsEmpty(originFeature)) {
    return null; // Exit if no feature is present
}
// Define the target table

var relTable = "whgis.sde.MOSAIC_STICK_BH_COUNT_P_F"
//var pointglobalid = FeatureSetByRelationshipName($feature, 'ZZZ_attRule_RELATE', ['globalID'], false)



return  {
  "result" : $feature.ent_name,
        "edit": [
          {
            //className we want to edit:
            "className": relTable,
             //the type of edit, 'adds'
            "adds": [
              {
                //the attribute we want to add, the name
                "attributes": 
                {
                  //"name": originFeature.name, copy the global id from mosaic_sticks_l into parent_globalid field

                 "ent_uuid": $feature.ent_uuid,
                 "parent_globalid":$feature.globalid

            
                },
                "geometry": Geometry($feature).paths[-1][-1]
                
              }
            ]

}
        

]
               


}
</expression><is_editable>True</is_editable><triggering_events_insert>True</triggering_events_insert><triggering_events_delete>False</triggering_events_delete><triggering_events_update>False</triggering_events_update><rule_description>Adds a point in the BH point layer that shows location of the BH</rule_description><field_name>ent_uuid</field_name><exclude_from_client_eval>True</exclude_from_client_eval><batch>False</batch><severity>-1</severity><category>-1</category></AddAttributeRule><ReorderAttributeRule><rule_name>Create New Entity</rule_name><evaluation_order>1</evaluation_order></ReorderAttributeRule></workflow></operationSequence>"

UpdateSchema "CIMDATA=<CIMStandardDataConnection xsi:type='typens:CIMStandardDataConnection' xmlns:xsi='http://www.w3.org/2001/XMLSchema-instance' xmlns:xs='http://www.w3.org/2001/XMLSchema' xmlns:typens='http://www.esri.com/schemas/ArcGIS/3.2.0'><WorkspaceConnectionString>ENCRYPTED_PASSWORD_UTF8=00022e68736c49467271537269326f57724d422b78666f4c4c507a4b4266547657467a4350484d745a436730616e733d2a00;ENCRYPTED_PASSWORD=00022e68644164487a526a584372337270524a595951666e3933517433425a664a5048502b4d6374644543545438383d2a00;SERVER=10.0.105.62;INSTANCE=sde:postgresql:10.0.105.62,5444;DBCLIENT=postgresql;DB_CONNECTION_PROPERTIES=10.0.105.62,5444;DATABASE=whgis;USER=sde;VERSION=sde.DEFAULT;AUTHENTICATION_MODE=DBMS</WorkspaceConnectionString><WorkspaceFactory>SDE</WorkspaceFactory><Dataset>whgis.sde.MOSAIC_STICKS_L_F</Dataset><DatasetType>esriDTFeatureClass</DatasetType></CIMStandardDataConnection>" "<operationSequence><workflow><AddAttributeRule><rule_name>Update Entity Location</rule_name><rule_type>CALCULATION</rule_type><expression>//The attribute rule is added to the pointClass on the Field field on update

//get the end points of a line
var pointGeometry = Geometry($feature).paths[-1][-1]
//get the guid of the point feature being updated
var globalId = $feature.globalid

//find the buffered geometry feature
var fs = FeatureSetbyName($datastore, "whgis.sde.MOSAIC_STICK_BH_COUNT_P_F")
//by filtering on the pointGuid
var pf = filter(fs, "parent_globalid = @globalId")
//if we couldn't find it exit (someone might've deleted it)
if (count(pf) == 0) return $feature.ent_uuid;
//get the feature row (we should only have one )
var pointFeature = first(pf)

return {
      //we want to just return the value of field `Field` no change require
      "result": $feature.ent_uuid,
      //this keyword indicates an edit that need to happen, its an array since we can make many edits
       "edit": [
           {  
              //the other class we want to edit
               "className" : "whgis.sde.MOSAIC_STICK_BH_COUNT_P_F",
               //the type of edit, in this case we want to update so we say `updates`, its an array since we can make many updates
               "updates" : [
                      { 
                            //what feature we need to update? we can either find it by the globalid or the objectId
                            "globalID" : pointFeature.globalId,
                            "ent_uuid": $feature.ent_uuid,
                            //what do we want to update (we can optionally add attributes property and update properties there)
                            "geometry": pointGeometry 

                     }

             ]


            }    
     ]

}
</expression><is_editable>True</is_editable><triggering_events_insert>False</triggering_events_insert><triggering_events_delete>False</triggering_events_delete><triggering_events_update>True</triggering_events_update><rule_description>Update BH point location in the related table when entity is moved</rule_description><field_name>ent_uuid</field_name><exclude_from_client_eval>True</exclude_from_client_eval><batch>False</batch><severity>-1</severity><category>-1</category></AddAttributeRule><ReorderAttributeRule><rule_name>Update Entity Location</rule_name><evaluation_order>2</evaluation_order></ReorderAttributeRule></workflow></operationSequence>"

